VALUES
  ('aboriginal-57f41407-moex-00002', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列那一行政區的民選首長不一定會是原住民？', '["豐濱鄉", "那瑪夏區", "牡丹鄉", "烏來區"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00003', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '假設原住民族委員會現任主任委員為山地原住民，下列敘述何者正確？', '["現任政務副主任委員必然是平地原住民", "下一任主任委員也有可能會是山地原住民", "下一任主任委員必然會是平地原住民", "現任常務副主任委員必然是平地原住民"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00004', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關鄉鎮市區原住民保留地土地權利審查委員會之敘述，何者正確？', '["掌理事項之一為申請撥用私有原住民保留地之審查事項", "得聘任現任執業地政士或律師擔任委員，以協助委員會專業審查工作", "委員會召開會議時，當事人及利害關係人未必會列席", "委員會就其職權審查或協議事項，其決議即為准駁之最後決定，以尊重原住民族集體意願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00005', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民姓名相關規定之敘述，何者錯誤？', '["使用傳統姓名登記者，可以使用中文文字", "原住民取用傳統姓名者，其改名並無次數限制", "原住民取用中文傳統姓名或漢人姓名，均得以傳統姓名之羅馬拼音並列登記", "原住民已依漢人姓名登記者，得申請回復其傳統姓名；回復傳統姓名者，得申請回復原有漢人姓名。但 均以1次為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00006', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '請問下列4人，誰有可能在進一步滿足一定條件後，即具有原住民身分？甲：4歲，父母均為原住民。乙： 17歲，父為原住民，母為漢人。丙：25歲，父為漢人，母為原住民。丁：6歲，生父生母均為漢人。', '["甲", "甲乙", "甲乙丙", "甲乙丙丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00007', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民族委員會促進原住民族國際交流補捐助實施要點之敘述，何者正確？', '["申請人若為本國個人，限為原住民", "本國機構、法人或團體之申請，最高補助經費為新臺幣50萬元", "申請人若為本國機構、法人或團體，出國人員三分之二以上須為原住民", "申請補助參與活動，應符合特定主題，並以國際會議、研討會、論壇、工作坊為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00008', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民族語言推廣人員設置規定的敘述，何者正確？', '["其法源依據為國家語言發展法", "依法該類人員應具原住民族語言能力認證測驗高級以上合格證書", "澎湖縣因非原住民族地區，故縣政府無法設置該類人員", "該類人員一旦獲聘，亦可擔任中小學族語教學工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00009', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依原住民漁民自製獵槍魚槍許可及管理辦法之規定，主管機關之權責分工，下列敘述何者錯誤？', '["安全事項由國防部主政", "原住民族委員會負責原住民自治事項", "內政部主政管理事項", "法務部負責法規研修"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00010', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '某甲為原住民，因某遊樂園大型氣爆案傷及雙耳，經醫生評估其聽能嚴重受損，影響工作能力。依原住民 族委員會輔助原住民急難救助實施要點，請問某甲最有可能獲得多少急難救助金？', '["新臺幣1萬元", "新臺幣2萬元", "新臺幣3萬元", "新臺幣5萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00011', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依照原住民漁民自製獵槍魚槍許可及管理辦法第 6 條的規定，原住民得申請製造、運輸或持有自製獵槍 者，其條件不包括下列何者？', '["成年", "未受監護或輔助宣告", "未經判處有期徒刑以上之刑確定", "申請製造、運輸或持有自製獵槍者需參加原住民族委員會或其委託之其他機關（構）、團體辦理之自製 獵槍安全使用訓練合格，且由原住民族委員會發給合格證明文件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
